A way to generate random `Id`s

   import Id exposing (Id)
   import Random exposing (Seed)

   user : Seed -> ( User, Seed )
   user seed =
       let
           ( id, nextSeed ) =
               Random.step Id.generator seed
       in
       ( { id = id, email = "Bob@sci.org" }
       , nextSeed
       )

